mapper.select:
SELECT id AS id, category_name AS categoryName, description AS description, status AS status
FROM book_category
WHERE id = #{id}

SELECT id AS id, title AS title, content AS content, status AS status
FROM notice
WHERE id = #{id}

mapper.update:
UPDATE notice
SET title = #{title}, content = #{content}, status = #{status}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT rr.id AS id, rr.borrow_record_id AS borrowRecordId, rr.reader_id AS readerId, r.reader_no AS readerNo, r.name AS readerName, b.book_name AS bookName, br.borrow_date AS borrowDate, br.due_date AS dueDate, rr.reason AS reason, rr.status AS status, rr.apply_time AS applyTime, rr.handle_time AS handleTime, rr.handler_name AS handlerName, rr.remark AS remark FROM renew_request rr LEFT JOIN borrow_record br ON rr.borrow_record_id = br.id LEFT JOIN reader r ON br.reader_id = r.id LEFT JOIN book b ON br.book_id = b.id
rr.status = #{status}
ORDER BY rr.apply_time DESC

mapper.update:
UPDATE borrow_record
SET due_date = DATE_ADD(due_date, INTERVAL 7 DAY), update_time = NOW()
WHERE id = #{borrowRecordId}

UPDATE borrow_record
SET renew_count = IFNULL(renew_count, 0) + 1, update_time = NOW()
WHERE id = #{borrowRecordId}

UPDATE fine_record
SET status = 'PAID', pay_time = NOW(), update_time = NOW()
WHERE id = #{id}
